// Yarın (bugün+1) ve 3 gün sonrasının (bugün+3) tarihlerini hesapla
const today = new Date();
today.setHours(0, 0, 0, 0);

const addDays = (d, n) => {
  const r = new Date(d);
  r.setDate(r.getDate() + n);
  return r;
};

const fmt = (d) => d.toISOString().split('T')[0];

const tomorrow     = addDays(today, 1);
const afterTomorrow = addDays(today, 2);
const threeDays    = addDays(today, 3);
const afterThree   = addDays(today, 4);

// Supabase'den randevuları çek: yarın veya 3 gün sonra olanlar
// PostgREST or() filtresi: iki ayrı gün aralığı
const baseUrl = 'https://yhmcpfxakmxryqnwpiaa.supabase.co/rest/v1/applications';
const select  = 'select=id,appointment_date,country,visa_type,clients(id,full_name,phone)';
const filter  = `or=(and(appointment_date.gte.${fmt(tomorrow)}T00:00:00,appointment_date.lt.${fmt(afterTomorrow)}T00:00:00),and(appointment_date.gte.${fmt(threeDays)}T00:00:00,appointment_date.lt.${fmt(afterThree)}T00:00:00))`;
const statusF = 'status=neq.approved&status=neq.rejected';

const url = `${baseUrl}?${select}&${filter}&${statusF}`;

const response = await $http.request({
  method: 'GET',
  url: url,
  headers: {
    'apikey': $env.SUPABASE_SERVICE_ROLE_KEY,
    'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
    'Accept': 'application/json'
  }
});

const appointments = Array.isArray(response) ? response : [];

if (appointments.length === 0) return [];

// Her randevu için mesaj payload'ı döndür
return appointments
  .filter(app => app.clients?.phone)
  .map(app => {
    const aptDate = new Date(app.appointment_date);
    const dateStr = aptDate.toLocaleDateString('tr-TR', {
      day: 'numeric',
      month: 'long',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
      timeZone: 'Europe/Istanbul'
    });
    return {
      json: {
        phone: app.clients.phone,
        clientName: app.clients.full_name,
        appointmentDate: dateStr,
        country: app.country,
        visaType: app.visa_type,
        applicationId: app.id
      }
    };
  });

const item = $json;

const phone = item.phone;
const clientName = item.clientName || 'Müşteri';
const appointmentDate = item.appointmentDate;
const country = item.country || '';
const visaType = item.visaType || '';

const message = `Efendim, ${appointmentDate} tarihinde ${country} konsolosluk randevunuz bulunmaktadır. Tüm evraklarınızı yanınızda bulundurunuz.`;

return [
  {
    json: {
      to: `whatsapp:${phone}`,
      from: 'whatsapp:+14155238886',
      body: message,
      clientName: clientName,
      applicationId: item.applicationId
    }
  }
];
